* CUSL -- 43x80 customer list (mod 4 / alt-screen, 35 rows per page).
* Mirrors custl.map's layout but exposes ROW1..ROW35 instead of 15.
MAP CUSTLL SIZE 43x80
  FIELD INFOLINE AT 0,0   LEN 78 PROT BRIGHT COLOR=WHITE
  FIELD AT 2,2   LEN 76 PROT BRIGHT COLOR=BLUE  "Customers"
  FIELD AT 4,2   LEN 78 PROT DIM COLOR=TURQUOISE    "CUST#    NAME                         CITY               PHONE"
  FIELD ROW1   AT 5,2   LEN 70 PROT COLOR=GREEN
  FIELD ROW2   AT 6,2   LEN 70 PROT COLOR=GREEN
  FIELD ROW3   AT 7,2   LEN 70 PROT COLOR=GREEN
  FIELD ROW4   AT 8,2   LEN 70 PROT COLOR=GREEN
  FIELD ROW5   AT 9,2   LEN 70 PROT COLOR=GREEN
  FIELD ROW6   AT 10,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW7   AT 11,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW8   AT 12,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW9   AT 13,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW10  AT 14,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW11  AT 15,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW12  AT 16,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW13  AT 17,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW14  AT 18,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW15  AT 19,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW16  AT 20,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW17  AT 21,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW18  AT 22,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW19  AT 23,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW20  AT 24,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW21  AT 25,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW22  AT 26,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW23  AT 27,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW24  AT 28,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW25  AT 29,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW26  AT 30,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW27  AT 31,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW28  AT 32,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW29  AT 33,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW30  AT 34,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW31  AT 35,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW32  AT 36,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW33  AT 37,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW34  AT 38,2  LEN 70 PROT COLOR=GREEN
  FIELD ROW35  AT 39,2  LEN 70 PROT COLOR=GREEN
  FIELD AT 41,2  LEN 76 PROT DIM COLOR=BLUE    "PF7=PageUp  PF8=PageDown  PF3=Exit"
ENDMAP
